import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { BQCComponent } from './bqc/bqc.component';
import { CUNComponent } from './cun/cun.component';
import { CUSComponent } from './cus/cus.component';



const routes: Routes = [{
  path: 'bqc',
  component: BQCComponent
}, {
  path: 'cun',
  component: CUNComponent
}, {
  path: 'cus',
  component: CUSComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class CUIRoutingModule { }
